import { useCallback, useSyncExternalStore } from "react";
import { getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:color-theme";
const DEFAULT_THEME_ID = "t3-dark";

// CSS custom properties that each theme injects onto :root as inline styles.
// Inline styles have higher specificity than stylesheet rules, so they override
// the @variant dark block in index.css for these specific tokens. All other
// tokens (--muted, --border, --destructive, etc.) remain governed by the .dark
// class mechanism in the stylesheet.
const THEME_CSS_VARS = [
  "--background",
  "--foreground",
  "--card",
  "--card-foreground",
  "--popover",
  "--popover-foreground",
  "--primary",
  "--ring",
  "--t3-sidebar",
  "--t3-editor",
  "--t3-terminal",
  "--t3-status-bar",
  "--t3-font-family",
  "--t3-font-size",
] as const;

let listeners: Array<() => void> = [];

function emitChange() {
  for (const listener of listeners) listener();
}

function getStoredId(): string {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw && getTheme(raw)) return raw;
  return DEFAULT_THEME_ID;
}

function getSnapshot(): string {
  return getStoredId();
}

function clearThemeVars() {
  const root = document.documentElement;
  for (const prop of THEME_CSS_VARS) {
    root.style.removeProperty(prop);
  }
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle .dark class — used by Tailwind @variant dark for tokens we don't
  // explicitly override (--muted, --border, --accent, --secondary, etc.).
  document.documentElement.classList.toggle("dark", theme.isDark);

  // Inject per-theme CSS custom properties as inline styles.
  const root = document.documentElement;
  root.style.setProperty("--background", theme.colors.background);
  root.style.setProperty("--foreground", theme.colors.foreground);
  root.style.setProperty("--card", theme.colors.background);
  root.style.setProperty("--card-foreground", theme.colors.foreground);
  root.style.setProperty("--popover", theme.colors.background);
  root.style.setProperty("--popover-foreground", theme.colors.foreground);
  root.style.setProperty("--primary", theme.colors.accent);
  root.style.setProperty("--ring", theme.colors.accent);
  // Theme-specific surface tokens (available for future component opt-in).
  root.style.setProperty("--t3-sidebar", theme.colors.sidebar);
  root.style.setProperty("--t3-editor", theme.colors.editor);
  root.style.setProperty("--t3-terminal", theme.colors.terminal);
  root.style.setProperty("--t3-status-bar", theme.colors.statusBar);
  root.style.setProperty("--t3-font-family", theme.fontFamily);
  root.style.setProperty("--t3-font-size", `${theme.fontSize}px`);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

function getResolvedTheme(id: string): "light" | "dark" {
  const theme = getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
  return theme.isDark ? "dark" : "light";
}

// Apply immediately on module load to prevent flash of wrong theme.
const _initialId = getStoredId();
applyTheme(getTheme(_initialId) ?? getTheme(DEFAULT_THEME_ID)!);

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Sync across browser tabs.
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      const id = getStoredId();
      const theme = getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
      applyTheme(theme, true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const theme = getTheme(themeId) ?? (getTheme(DEFAULT_THEME_ID) as Theme);
  const resolvedTheme: "light" | "dark" = theme.isDark ? "dark" : "light";

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id) ?? (getTheme(DEFAULT_THEME_ID) as Theme);
    localStorage.setItem(STORAGE_KEY, next.id);
    applyTheme(next, true);
    emitChange();
  }, []);

  return {
    /** The currently active Theme object. */
    theme,
    /** Switch to a different theme by id. */
    setTheme,
    /** All built-in themes in display order. */
    availableThemes: listThemes(),
    /**
     * Resolved as "light" or "dark" based on the theme's isDark flag.
     * Preserved for diff rendering and syntax highlighting consumers.
     */
    resolvedTheme,
  } as const;
}

export type { Theme };

// Re-export for consumers that only need the resolved dark/light value without
// the full theme object (used by DiffWorkerPoolProvider, ChatMarkdown, etc.).
export { getResolvedTheme, clearThemeVars };

