import { type ThemeColors } from "@t3tools/shared/themes";
import { useTheme } from "../hooks/useTheme";
import { cn } from "../lib/utils";

/** Renders four color swatches giving a quick visual preview of a theme. */
function ThemeSwatchPreview({ colors }: { colors: ThemeColors }) {
  return (
    <div className="flex shrink-0 gap-0.5 overflow-hidden rounded border border-black/10 dark:border-white/10">
      {/* Background */}
      <span
        className="block h-6 w-5"
        style={{ background: colors.background }}
        title="Background"
      />
      {/* Sidebar */}
      <span
        className="block h-6 w-5"
        style={{ background: colors.sidebar }}
        title="Sidebar"
      />
      {/* Accent */}
      <span
        className="block h-6 w-5"
        style={{ background: colors.accent }}
        title="Accent"
      />
      {/* Foreground — rendered as a thin strip so it reads as "text" */}
      <span
        className="block h-6 w-2"
        style={{ background: colors.foreground }}
        title="Foreground"
      />
    </div>
  );
}

/**
 * A theme picker that lists all available themes with color swatch previews.
 * Wires directly to `useTheme()` — no props needed.
 */
export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {availableThemes.map((t) => {
        const selected = theme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={cn(
              "flex w-full items-center gap-3 rounded-lg border px-3 py-2 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent",
            )}
            onClick={() => setTheme(t.id)}
          >
            <ThemeSwatchPreview colors={t.colors} />

            <span className="flex min-w-0 flex-col">
              <span className="text-sm font-medium">{t.name}</span>
              <span className="text-xs text-muted-foreground">
                {t.isDark ? "Dark" : "Light"} · {t.fontSize}px
              </span>
            </span>

            {selected ? (
              <span className="ml-auto shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Selected
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

